import{_ as i,o as e,c as l,a2 as r}from"./chunks/framework.VxKNwi4m.js";const p=JSON.parse('{"title":"IBS: IBS 워크스페이스 (Workspace)","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1783863495000}'),t={name:"index.md"};function n(o,a,s,h,d,u){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="ibs-ibs-워크스페이스-workspace" tabindex="-1">IBS: IBS 워크스페이스 (Workspace) <a class="header-anchor" href="#ibs-ibs-워크스페이스-workspace" aria-label="Permalink to &quot;IBS: IBS 워크스페이스 (Workspace)&quot;">​</a></h1><p><strong>IBS 워크스페이스</strong>는 부동산 개발(시행) 프로젝트의 전 과정에서 발생하는 자금, 계약, 고객, 문서, 소송 등 핵심 데이터를 통합 관리하고 협업하는 <strong>디벨로퍼를 위한 통합 업무 공간</strong>입니다.</p><p>글로벌 협업 표준인 <strong>Redmine 엔진</strong>을 기반으로 설계된 IBS 워크스페이스는 단순한 데이터 기록을 넘어, 모든 비즈니스 프로세스를 <strong>&#39;업무(Issue)&#39; 단위로 연결</strong>합니다. 이를 통해 팀원들 간의 소통을 원활하게 하고, 모든 의사결정의 근거를 체계적으로 자산화합니다.</p><h2 id="왜-ibs-워크스페이스인가" tabindex="-1">왜 IBS 워크스페이스인가? <a class="header-anchor" href="#왜-ibs-워크스페이스인가" aria-label="Permalink to &quot;왜 IBS 워크스페이스인가?&quot;">​</a></h2><p>부동산 개발사업은 상품 유형(공동주택, 상가, 오피스 등)과 사업 방식(일반분양, 조합, 임대 등)에 따라 관리 프로세스가 매우 복잡합니다.</p><p><strong>IBS 워크스페이스</strong>는 이러한 복잡함을 걷어내고, 사용자가 가장 편안한 환경에서 데이터에 집중할 수 있도록 돕습니다.</p><ul><li><strong>친숙한 협업 환경:</strong> 레드마인 기반의 이슈 트래킹으로 업무의 시작과 끝을 명확히 관리합니다.</li><li><strong>통합된 데이터 흐름:</strong> 분양 현황, 수납 데이터, 회계 장부가 하나의 워크스페이스에서 흐릅니다.</li><li><strong>협업의 가치:</strong> 모든 계약과 수지 데이터에는 담당자들의 논의 이력이 함께 보존됩니다.</li><li><strong>신속한 의사결정:</strong> 실시간 대시보드를 통해 사업 수지와 자금 현황을 즉시 파악합니다.</li></ul><h2 id="주요-기능" tabindex="-1">주요 기능 <a class="header-anchor" href="#주요-기능" aria-label="Permalink to &quot;주요 기능&quot;">​</a></h2><h3 id="🎯-이슈-기반-협업-관리-redmine-engine" tabindex="-1">🎯 이슈 기반 협업 관리 (Redmine Engine) <a class="header-anchor" href="#🎯-이슈-기반-협업-관리-redmine-engine" aria-label="Permalink to &quot;🎯 이슈 기반 협업 관리 (Redmine Engine)&quot;">​</a></h3><ul><li>프로젝트별 업무 게시판 및 부서 간 협업 프로세스 운영</li><li>업무 히스토리 추적을 통한 지식 자산화</li><li>사용자별 맞춤형 업무 할당 및 알림 기능</li></ul><h3 id="🏗️-사업지-및-마스터플랜-설정" tabindex="-1">🏗️ 사업지 및 마스터플랜 설정 <a class="header-anchor" href="#🏗️-사업지-및-마스터플랜-설정" aria-label="Permalink to &quot;🏗️ 사업지 및 마스터플랜 설정&quot;">​</a></h3><ul><li>프로젝트 유형별 상세 속성 및 유닛 타입 정의</li><li>동·호수 배치 및 층별 공급가 관리</li><li>계약 회차 및 고지 조건 설정</li></ul><h3 id="🗺️-부지-매입-및-토지-수지-관리" tabindex="-1">🗺️ 부지 매입 및 토지 수지 관리 <a class="header-anchor" href="#🗺️-부지-매입-및-토지-수지-관리" aria-label="Permalink to &quot;🗺️ 부지 매입 및 토지 수지 관리&quot;">​</a></h3><ul><li>필지별 소유자 정보 및 매입 진행 현황 관리</li><li>지주 작업 이력 및 보상 계약 추적</li><li>토지 대금 집행 및 미지급금 현황 관리</li></ul><h3 id="🤝-분양-계약-및-고객-관리-crm" tabindex="-1">🤝 분양 계약 및 고객 관리 (CRM) <a class="header-anchor" href="#🤝-분양-계약-및-고객-관리-crm" aria-label="Permalink to &quot;🤝 분양 계약 및 고객 관리 (CRM)&quot;">​</a></h3><ul><li>분양 계약자 정보 통합 등록 및 관리</li><li>유닛 매칭 및 동·호수별 분양 상태 시각화</li><li>해약, 승계 및 부적격자 관리 로직 지원</li></ul><h3 id="💰-자금-수납-및-회계-자동-연동" tabindex="-1">💰 자금 수납 및 회계 자동 연동 <a class="header-anchor" href="#💰-자금-수납-및-회계-자동-연동" aria-label="Permalink to &quot;💰 자금 수납 및 회계 자동 연동&quot;">​</a></h3><ul><li>입금 데이터 자동 매칭 및 수납 확인서 발행</li><li>연체료 자동 계산 및 고지 관리</li><li>수납 데이터의 내부 회계 시스템 자동 반영</li></ul><h3 id="📊-사업-수지-분석-및-예산-통제" tabindex="-1">📊 사업 수지 분석 및 예산 통제 <a class="header-anchor" href="#📊-사업-수지-분석-및-예산-통제" aria-label="Permalink to &quot;📊 사업 수지 분석 및 예산 통제&quot;">​</a></h3><ul><li>초기 수지표 기반의 예산 편성 및 항목 관리</li><li>예산 대비 실제 집행 실적(Actuals) 실시간 비교</li><li>자금 조달 계획 및 현금 흐름(Cash-flow) 분석</li></ul><h3 id="⚖️-문서-보관소-및-소송-관리" tabindex="-1">⚖️ 문서 보관소 및 소송 관리 <a class="header-anchor" href="#⚖️-문서-보관소-및-소송-관리" aria-label="Permalink to &quot;⚖️ 문서 보관소 및 소송 관리&quot;">​</a></h3><ul><li>프로젝트별 중요 문서 및 법률 자료 통합 관리</li><li>소송 사건별 기일 및 진행 현황 추적</li><li>민원 및 분쟁 처리 히스토리 관리</li></ul><h2 id="ibs의-의미" tabindex="-1">IBS의 의미 <a class="header-anchor" href="#ibs의-의미" aria-label="Permalink to &quot;IBS의 의미&quot;">​</a></h2><p><strong>IBS</strong>는 <strong>I</strong>ntelligent <strong>B</strong>usiness <strong>S</strong>ystem의 약어입니다.</p><p>단순히 똑똑한 프로그램을 넘어, 사용자가 더 가치 있는 일에 집중할 수 있도록 돕는 **&#39;지능형 업무 파트너&#39;**가 되겠다는 의지를 담고 있습니다.</p><h2 id="우리의-지향점" tabindex="-1">우리의 지향점 <a class="header-anchor" href="#우리의-지향점" aria-label="Permalink to &quot;우리의 지향점&quot;">​</a></h2><p>부동산 개발은 수많은 사람의 노력과 정교한 데이터가 만나 새로운 가치를 만드는 일입니다.</p><p><strong>IBS 워크스페이스</strong>는 디벨로퍼들이 반복적인 관리 업무에서 자유로워지고, 더 나은 공간과 상품을 기획하는 창의적인 업무에 집중할 수 있는 환경을 만들고자 합니다.</p><p>우리는 실제 현장의 목소리를 담아 부동산 시행 업무의 가장 편리한 표준을 만들어 갑니다.</p><hr><p>프로그램 설치 및 기본 사용법은 <a href="/intro/getting-started.html">시작하기</a>에서 확인할 수 있습니다.</p>',31)])])}const g=i(t,[["render",n]]);export{p as __pageData,g as default};
